//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: OMML (§22.1 Math) — structure fidelity + Word variations for
//! `m:oMath` / `m:oMathPara` round-trip.
//!
//! Each `#[test]` encodes a single declarative TestSpec mined from
//! ECMA-376 / ISO 29500 / MS-OI29500 / MS-OE376. The body XML is imported via
//! `stemma::api::Document::parse`, re-serialized with `ExportOptions::default()`,
//! and the resulting `word/document.xml` is asserted against the spec rule.
//!
//! A FAILING assertion here encodes a REAL Word-compliance gap in stemma: the
//! engine diverged from what ECMA/Word require for OMML structure fidelity.
//! Do NOT weaken an assertion to make it pass — a fail is the finding.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED OMML
//! verbatim (the math zone is an opaque inline/block). The `xml*` expectations
//! below all target markup the serializer must reproduce from that opaque tree
//! — structural elements, child ordering (Annex A), namespace binding, and
//! significant whitespace — i.e. "the engine must not corrupt this structure",
//! which is exactly what verbatim preservation is contracted to guarantee.

use std::io::{Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude: docx zip plumbing ─────────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body>…</w:body></w:document>`. `extra_parts` adds extra
/// `word/<name>` parts (e.g. `("styles.xml", "<…>")`) plus their content-type
/// overrides. The math namespace is declared inline on each OMML root in the
/// spec body XML, so no document-level `m:` binding is required here.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content types: defaults + document override + one override per extra part.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (name, _) in extra_parts {
        let content_type = match *name {
            "styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: unknown extra part {other} — add its content type"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/word/{name}" ContentType="{content_type}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, content) in extra_parts {
            zip.start_file(format!("word/{name}"), opts).unwrap();
            zip.write_all(content.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml`.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Import → re-serialize → return the re-serialized `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Whitespace-insensitive ordered-substring check: returns true iff every
/// `needle` appears in `haystack` in order, ignoring runs of ASCII whitespace
/// *between* needles (whitespace *inside* a needle is matched literally). This
/// is the regex-free translation of the spec `xmlRegex` patterns, whose only
/// regex metacharacters are `\s*`/`.*` (sequence-of-children) and literal text.
/// `\s*` and `.*` in a pattern become the gaps between the literal fragments.
fn contains_in_order(haystack: &str, needles: &[&str]) -> bool {
    let mut pos = 0usize;
    for needle in needles {
        match haystack[pos..].find(needle) {
            Some(rel) => pos += rel + needle.len(),
            None => return false,
        }
    }
    true
}

