#[test]
fn omathpara_jc_property_preserved_in_display_math() {
    let body = r#"<w:p><w:r><w:t>The equation is</w:t></w:r><m:oMathPara xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:oMathParaPr><m:jc m:val="right"/></m:oMathParaPr><m:oMath><m:r><m:t>E=mc^2</m:t></m:r></m:oMath></m:oMathPara></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        xml.contains("<m:oMathParaPr>"),
        "§22.1.2.79 (oMathParaPr): oMathParaPr is the structural carrier of math-paragraph properties; re-serializing the OmmlBlock opaque must reproduce it. expected XML to contain <m:oMathParaPr>. Got:\n{xml}"
    );
    assert!(
        contains_in_order(&xml, &["<m:jc", "m:val=\"right\""]),
        "§22.1.2.51 (jc) + §22.1.3.7 (ST_Jc): the right justification (a valid ST_Jc value) must be preserved verbatim, not dropped or normalized to the centerGroup default. expected XML to match <m:jc[^>]*m:val=\"right\". Got:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "§22.1.2.79: a faithfully re-emitted m:oMathPara with valid oMathParaPr/jc must open in Word without repair. validate issues: {:?}",
        report.issues
    );
}

#[test]
fn omathpara_emitted_as_direct_child_of_paragraph() {
    let body = r#"<w:p><m:oMathPara xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:oMath><m:r><m:t>a+b=c</m:t></m:r></m:oMath></m:oMathPara></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        xml.contains("<m:oMathPara"),
        "§22.1.2.78 (oMathPara): the display-math paragraph must survive round-trip. expected XML to contain <m:oMathPara. Got:\n{xml}"
    );
    assert!(
        contains_in_order(&xml, &["<w:p>", "<m:oMathPara"]),
        "§22.1.2.78 (oMathPara): oMathPara is a paragraph-level math paragraph and must be a direct child of w:p, not nested inside a w:r run (pattern <w:p>\\s*<m:oMathPara). Got:\n{xml}"
    );
    // Stronger structural check: no w:r run may sit between the <w:p> and the
    // oMathPara — the display-math paragraph is not run content (§22.1.2.78).
    let p_idx = xml.find("<w:p>").expect("w:p present");
    let omp_idx = xml[p_idx..]
        .find("<m:oMathPara")
        .expect("oMathPara present")
        + p_idx;
    let between = &xml[p_idx + "<w:p>".len()..omp_idx];
    assert!(
        !between.contains("<w:r>") && !between.contains("<w:r "),
        "§22.1.2.78: oMathPara must be a direct child of w:p, not wrapped in a w:r run; found run markup before it: {between:?}. Got:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "§22.1.2.78: an m:oMathPara emitted as a direct child of w:p is structurally valid and opens in Word without repair. validate issues: {:?}",
        report.issues
    );
}

#[test]
fn math_text_significant_whitespace_xmlspace_preserved() {
    let body = r#"<w:p><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:r><m:t xml:space="preserve">  a + b  </m:t></m:r></m:oMath></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        contains_in_order(&xml, &["<m:t", "xml:space=\"preserve\""]),
        "§22.1.2.116 (t): the xml:space=\"preserve\" marker on the math text run must be preserved so the significant whitespace stays significant on round-trip (pattern <m:t[^>]*xml:space=\"preserve\"). Got:\n{xml}"
    );
    assert!(
        xml.contains(">  a + b  <"),
        "§22.1.2.116: with xml:space=\"preserve\" the exact leading/trailing whitespace bytes are significant and must round-trip unchanged. expected XML to contain >  a + b  <. Got:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "§22.1.2.116: a well-formed inline m:oMath with xml:space-preserved text opens in Word without repair. validate issues: {:?}",
        report.issues
    );
}

#[test]
fn math_namespace_prefix_preserved_on_roundtrip() {
    let body = r#"<w:p><w:r><w:t>inline </w:t></w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:r><m:t>x+1</m:t></m:r></m:oMath></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        xml.contains("http://schemas.openxmlformats.org/officeDocument/2006/math"),
        "§22.1 (OMML namespace): OMML elements must remain bound to the math namespace on round-trip; the namespace URI must appear in the re-serialized output. Got:\n{xml}"
    );
    assert!(
        xml.contains("<m:oMath>") || xml.contains("<m:oMath "),
        "§22.1.2.77 (oMath): the oMath element (math zone) must survive re-serialization in the m: prefix used by Word (pattern <m:oMath[ >]). Got:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "§22.1: a correctly-namespaced inline m:oMath opens in Word without repair. validate issues: {:?}",
        report.issues
    );
}

#[test]
fn nested_fraction_structure_roundtrips_verbatim() {
    let body = r#"<w:p><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:f><m:num><m:f><m:num><m:r><m:t>a</m:t></m:r></m:num><m:den><m:r><m:t>b</m:t></m:r></m:den></m:f></m:num><m:den><m:r><m:t>c</m:t></m:r></m:den></m:f></m:oMath></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        contains_in_order(&xml, &["<m:f>", "<m:num>", "<m:f>"]),
        "§22.1.2.36 (f, Fraction): the outer fraction's numerator is itself a fraction; the nesting must be preserved, not flattened (pattern <m:f>\\s*<m:num>\\s*<m:f>). Got:\n{xml}"
    );
    assert!(
        contains_in_order(&xml, &["<m:num>", "<m:den>"]),
        "§22.1.2.36: a fraction object is num then den in order; the child ordering must round-trip unchanged (pattern <m:num>.*<m:den>). Got:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "§22.1.2.36: a well-formed nested-fraction m:oMath opens in Word without repair. validate issues: {:?}",
        report.issues
    );
}

#[test]
fn omml_ctrlpr_inner_wrpr_preserved_roundtrip() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">x = </w:t></w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:f><m:fPr><m:ctrlPr><w:rPr><w:rFonts w:ascii="Cambria Math" w:hAnsi="Cambria Math"/><w:i/></w:rPr></m:ctrlPr></m:fPr><m:num><m:r><m:t>a</m:t></m:r></m:num><m:den><m:r><m:t>b</m:t></m:r></m:den></m:f></m:oMath></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        xml.contains("<m:ctrlPr>"),
        "§22.1.2.23 (ctrlPr): ctrlPr is the documented carrier of control-character formatting; verbatim preservation must keep the element. Got:\n{xml}"
    );
    assert!(
        contains_in_order(&xml, &["m:ctrlPr>", "<w:rPr>", "Cambria Math"]),
        "§22.1.2.23: ECMA shows m:ctrlPr nests a w:rPr; the inner w:rPr (with the Cambria Math rFonts) must roundtrip so the control-character formatting is not lost (pattern m:ctrlPr>\\s*<w:rPr>.*Cambria Math). Got:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "§22.1.2.23: a well-formed fraction with a ctrlPr/w:rPr is valid OMML and must re-serialize to a document Word opens without repair. validate issues: {:?}",
        report.issues
    );
}

#[test]
fn omml_mt_xml_space_preserve_roundtrip() {
    let body = r#"<w:p><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:r><m:t xml:space="preserve">a  +  b</m:t></m:r></m:oMath></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        contains_in_order(&xml, &["<m:t", "xml:space=\"preserve\"", ">a  +  b</m:t>"]),
        "ECMA §22.1.2.116 (t): m:t whitespace handling is governed by xml:space; the preserve marker and the doubled spaces must roundtrip verbatim or the equation spacing changes (pattern <m:t[^>]*xml:space=\"preserve\"[^>]*>a  \\+  b</m:t>). Got:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "§22.1.2.116: a math run with xml:space=\"preserve\" on m:t is valid; the re-serialized document must open clean in Word. validate issues: {:?}",
        report.issues
    );
}

#[test]
fn omml_pmark_omath_runprop_only_on_paragraph_mark_preserved() {
    let body = r#"<w:p><w:pPr><w:rPr><w:specVanish/><w:oMath/></w:rPr></w:pPr></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        contains_in_order(
            &xml,
            &["<w:pPr>", "<w:rPr>", "<w:oMath", "</w:rPr>", "</w:pPr>"]
        ),
        "ECMA §17.3.2.22: the math-paragraph-mark setting roundtrips as w:oMath inside the paragraph-mark rPr; it must be preserved there (pattern <w:pPr><w:rPr>.*<w:oMath\\s*/>.*</w:rPr></w:pPr>). Got:\n{xml}"
    );
    assert!(
        contains_in_order(&xml, &["<w:specVanish", "<w:oMath"]),
        "ECMA Annex A CT_RPr orders specVanish (pos 38) before oMath (pos 39); the serializer must keep oMath after specVanish (pattern <w:specVanish\\s*/>\\s*<w:oMath\\s*/>). Got:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA §17.3.2.22: a paragraph-mark rPr carrying w:oMath is valid CT_RPr; the document must open clean. validate issues: {:?}",
        report.issues
    );
}

