#[test]
fn omml_nested_fraction_structure_not_corrupted_when_text_edited() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">value </w:t></w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:f><m:num><m:f><m:num><m:r><m:t>a</m:t></m:r></m:num><m:den><m:r><m:t>b</m:t></m:r></m:den></m:f></m:num><m:den><m:r><m:t>c</m:t></m:r></m:den></m:f></m:oMath></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        xml.contains("<m:f><m:num><m:f><m:num><m:r><m:t>a</m:t>"),
        "ECMA §22.1.2.77 (oMath): the oMath subtree is container-independent and must roundtrip with its nested m:f/m:num/m:den intact; the inner fraction's numerator must remain the same nested structure. expected XML to contain <m:f><m:num><m:f><m:num><m:r><m:t>a</m:t>. Got:\n{xml}"
    );
    assert!(
        xml.contains("<m:den><m:r><m:t>c</m:t></m:r></m:den></m:f></m:oMath>"),
        "ECMA §22.1.2.77: the outer fraction's denominator and the closing of the nested fraction structure must survive verbatim. Got:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "§22.1.2.77: a well-formed nested fraction inside inline oMath is valid OMML; the re-serialized document must open clean in Word. validate issues: {:?}",
        report.issues
    );
}

#[test]
fn omath_text_xml_space_preserve_roundtrips() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">before </w:t></w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:r><m:t xml:space="preserve"> x + y </m:t></m:r></m:oMath><w:r><w:t xml:space="preserve"> after</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        xml.contains("xml:space=\"preserve\""),
        "ECMA §22.1.2.92 (m:t) / m_CT_Text: m_CT_Text permits xml:space; the significant-whitespace marker Word wrote on m:t must survive import/serialize, not be stripped. Got:\n{xml}"
    );
    assert!(
        contains_in_order(&xml, &["<m:t", "> x + y </m:t>"]),
        "ECMA §22.1.2.92: the leading and trailing spaces inside the math text are significant under xml:space=\"preserve\" and must round-trip verbatim, not be collapsed or trimmed (pattern <m:t[^>]*> x \\+ y </m:t>). Got:\n{xml}"
    );
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA §22.1.2.92: xml:space on m:t is schema-valid per m_CT_Text; the round-tripped equation must still open clean in Word. validate issues: {:?}",
        report.issues
    );
}

